mapper.delete:
/* TM_CL12001_Dao_deleteWthtEqpSttusList */
DELETE FROM
	tm_cl12001
WHERE
	wtht_suply_begin_de = #{wthtSuplyBeginDe}
	AND eqp_nm = #{eqpNm}
